INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$No-Code App Builder$q$, $q$Assemble pages, forms, and navigation using drag-and-drop blocks without writing frontend or backend code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$AI App Generation$q$, $q$Generate app pages, layouts, and workflow automations from a natural-language prompt using Softr's built-in AI co-builder.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Multiple Data Source Connections$q$, $q$Connect to Airtable, Google Sheets, Notion, HubSpot, PostgreSQL, MySQL, BigQuery, and other sources to power app content.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$User Authentication and Permissions$q$, $q$Built-in login, sign-up, and role-based access control let you gate content behind custom user groups.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Workflow Automation$q$, $q$Trigger multi-step actions such as sending emails, updating records, or calling external APIs when app events occur.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Custom Code Support$q$, $q$Add custom CSS, JavaScript, and code blocks on paid plans for design or functionality beyond the standard block library.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Payments and Subscriptions$q$, $q$Accept one-time payments or recurring subscriptions inside an app using built-in Stripe integration.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Templates Library$q$, $q$Start from pre-built templates for client portals, internal tools, directories, and marketplaces to launch faster.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Fast way to launch functional apps from existing spreadsheets or databases without hiring developers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$AI co-builder speeds up initial app creation from a text prompt$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Wide range of data source integrations, including Airtable, HubSpot, and SQL databases$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Free plan is generous enough to fully test the platform before paying$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Built-in authentication, permissions, and payments reduce the need for third-party tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Pricing scales quickly with app users and AI credits, which can get expensive for larger portals$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Complex custom logic still requires writing custom code or workarounds$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Performance can depend on the connected data source, especially with large Airtable bases$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Some advanced data sources like BigQuery and PostgreSQL are limited to higher-tier plans$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$What is Softr used for$q$, $q$Softr is used to build client portals, internal tools, directories, and marketplaces on top of existing data in Airtable, Google Sheets, Notion, or a SQL database, without writing code.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Is Softr free$q$, $q$Yes, Softr offers a free plan that supports unlimited apps with up to 10 users and 5,000 database records. Paid plans start at 49 dollars per month for higher usage limits.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Who founded Softr$q$, $q$Softr was founded in 2019 in Berlin, Germany by Mariam Hakobyan and Artur Mkrtchyan.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Does Softr require coding skills$q$, $q$No, Softr is a no-code platform, though paid plans allow adding custom code blocks for advanced customization.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$What data sources does Softr support$q$, $q$Softr connects to Airtable, Google Sheets, Notion, HubSpot, PostgreSQL, MySQL, BigQuery, and more than 15 other data sources depending on the plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Can Softr apps have user logins$q$, $q$Yes, Softr includes built-in user authentication and role-based permissions so you can control what different user groups can access.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Does Softr support payments$q$, $q$Yes, Softr integrates with Stripe to accept one-time payments or recurring subscriptions inside an app.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$What is the difference between Softr's Professional and Business plans$q$, $q$The Business plan supports more app users, more AI credits and workflow actions, and adds data sources like HubSpot, BigQuery, PostgreSQL, and MySQL, while Professional is aimed at smaller portals and internal tools.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Client Portals$q$, $q$Agencies and service businesses give clients a branded portal to view project status, invoices, or shared files sourced from Airtable or a database.$q$, $q$Agencies and service providers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Internal Tools and Dashboards$q$, $q$Operations teams build internal dashboards and admin tools on top of existing spreadsheets or databases without waiting on engineering resources.$q$, $q$Operations and business teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Directories and Marketplaces$q$, $q$Startups launch searchable directories or two-sided marketplaces quickly using Softr's directory templates and built-in payments.$q$, $q$Startups and directory site owners$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Free$q$, $q$$0/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited apps","Up to 10 app users","5,000 database records","5 AI credits per month","Unlimited collaborators"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Basic$q$, $q$$49/month$q$, $q$Monthly or $588/year$q$, NULL, $q$["Up to 20 app users","50,000 database records","10 AI credits per month","Custom code support","2,500 workflow actions per month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Professional$q$, $q$$139/month$q$, $q$Monthly or $1,668/year$q$, NULL, $q$["Up to 100 app users","500,000 database records","50 AI credits per month","3 custom user groups","Advanced integrations like monday.com and Supabase","10,000 workflow actions per month"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Business$q$, $q$$269/month$q$, $q$Monthly or $3,228/year$q$, NULL, $q$["Up to 500 app users","1 million database records","100 AI credits per month","Unlimited user groups","SQL and HubSpot data sources","25,000 workflow actions per month"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Enterprise$q$, $q$Custom$q$, $q$Annual contract$q$, NULL, $q$["Custom usage limits","SSO with SAML and OpenID","SOC2 reporting","Audit logging","Dedicated success manager"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$overview$q$, $q$What Is Softr$q$, 2, ARRAY[$q$Softr is a no-code and AI-assisted platform for building business web applications directly on top of existing data sources such as Airtable, Google Sheets, Notion, HubSpot, and SQL databases. Instead of writing custom backend and frontend code, teams assemble pages, forms, and workflows using pre-built blocks and an AI co-builder that can generate an app from a text prompt.$q$, $q$Founded in 2019 in Berlin by Mariam Hakobyan and Artur Mkrtchyan, Softr has grown into one of the most widely used no-code platforms for client portals, internal tools, and directories. The company raised a Series A round led by FirstMark Capital and continues to add AI-native app generation and workflow automation features.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Softr apps include built-in user authentication and role-based access control, so teams can restrict what different user groups can see or edit inside a portal or internal tool.$q$, $q$The platform connects to more than 15 data sources, including Airtable, Google Sheets, Notion, HubSpot, PostgreSQL, MySQL, and BigQuery on higher-tier plans, letting existing spreadsheets or databases power a fully functional app.$q$, $q$An AI co-builder can generate pages, layouts, and automations from natural-language prompts, and a library of pre-built blocks covers common patterns like directories, marketplaces, dashboards, and client portals.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Softr uses a freemium model. The Free plan supports unlimited apps with up to 10 users and 5,000 database records. Paid plans scale from Basic at 49 dollars per month up to Business at 269 dollars per month, with an Enterprise tier offering custom limits, SSO, and dedicated support.$q$, $q$Pricing is driven primarily by the number of app users, database records, and monthly AI credits and workflow actions included in each tier, rather than by the number of builders or collaborators, which are unlimited on every plan.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Webmail and Groupware$q$, $q$Provides an AJAX-based web interface for email, calendars, address books, and tasks in a single self-hosted server.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$CalDAV and CardDAV Support$q$, $q$Syncs calendars and contacts with native clients including Thunderbird, Apple Calendar and Contacts, and other CalDAV/CardDAV compatible apps.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Microsoft ActiveSync$q$, $q$Supports Microsoft Exchange ActiveSync so iOS, Android, and other mobile devices can sync mail, contacts, calendars, and tasks.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Directory Integration$q$, $q$Connects to Active Directory, OpenLDAP, and SQL databases for authentication and user management instead of requiring a separate user store.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Single Sign-On$q$, $q$Supports SSO via CAS, WebAuth, or Kerberos, along with two-factor authentication and configurable password policies.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Multi-Domain Hosting$q$, $q$Designed to scale to thousands of mailboxes and multiple domains, making it suitable for ISPs and hosting providers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Outlook and Thunderbird Plugins$q$, $q$Offers a free connector plugin for Microsoft Outlook and native integration with Mozilla Thunderbird.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Open Standards$q$, $q$Built entirely on open protocols, avoiding vendor lock-in compared to proprietary groupware servers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Free and open source with no per-user licensing cost for the core server$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Broad native client support through CalDAV, CardDAV, and ActiveSync$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Integrates with existing LDAP, Active Directory, and IMAP infrastructure$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Proven at scale in production environments with thousands of mailboxes$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Active commercial steward (Alinto) available for organizations that want paid support$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Requires in-house IT expertise or a paid support contract to install, secure, and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Web interface looks dated compared to modern SaaS email clients$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$No official cloud-hosted SaaS version directly from the core project, only third-party hosting$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Documentation can be technical and geared toward system administrators rather than end users$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Is SOGo free to use$q$, $q$Yes, SOGo's core groupware server is free and open source under the GNU GPL and LGPL version 2 licenses. You only pay for hosting or optional commercial support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$What protocols does SOGo support$q$, $q$SOGo supports CalDAV, CardDAV, GroupDAV, and Microsoft ActiveSync, allowing it to sync with Thunderbird, Outlook, Apple Calendar and Contacts, and mobile devices.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Who maintains SOGo$q$, $q$SOGo is maintained by its open-source community, with the French company Alinto serving as commercial steward since 2022, following earlier stewardship by the Canadian company Inverse.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Can SOGo replace Microsoft Exchange$q$, $q$SOGo is often used as a self-hosted alternative to Exchange for organizations that want webmail, calendaring, and mobile sync without an Exchange license, though feature parity varies by use case.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Does SOGo work with Outlook$q$, $q$Yes, SOGo offers a free connector plugin for Microsoft Outlook in addition to native support for Thunderbird and CalDAV or CardDAV compatible clients.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$What infrastructure does SOGo require$q$, $q$SOGo typically runs alongside an existing IMAP mail server and can use Active Directory, OpenLDAP, or SQL databases for user accounts.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Is there a hosted version of SOGo$q$, $q$The core SOGo project is self-hosted, but the commercial steward Alinto offers a hosted variant called SOGomail for organizations that do not want to manage their own server.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Self-Hosted Business Email$q$, $q$Small and mid-size businesses replace hosted email suites with a self-hosted SOGo server for full control over data and infrastructure.$q$, $q$IT teams and system administrators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$ISP and Hosting Provider Webmail$q$, $q$Hosting providers deploy SOGo to offer webmail, calendar, and contact services to thousands of customer mailboxes across multiple domains.$q$, $q$ISPs and web hosting companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Exchange Alternative for Regulated Industries$q$, $q$Organizations with data residency or compliance requirements use SOGo to keep email and calendar data on infrastructure they control.$q$, $q$Government and regulated enterprises$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["GPL/LGPL v2 licensed source code","Unlimited users limited only by your infrastructure","Community support via mailing lists and forums","Full access to CalDAV, CardDAV, and ActiveSync features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$Commercial Support (via Alinto)$q$, $q$Custom pricing$q$, $q$Contract$q$, NULL, $q$["Vendor-backed support and maintenance","Access to the SOGomail hosted variant","Priority bug fixes and security patches"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$overview$q$, $q$What Is SOGo$q$, 2, ARRAY[$q$SOGo is a free and open-source groupware server that provides webmail, calendaring, and contact management for organizations that prefer to self-host their collaboration infrastructure instead of using a hosted email suite.$q$, $q$The project has a long history, tracing back to the SKYRiX and OpenGroupware.org groupware servers built by Skyrix Software in Magdeburg, Germany. The current SOGo project started in 2004 as a scalability-focused fork, was maintained by the Canadian company Inverse for many years, and has been commercially stewarded by the French company Alinto since 2022.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$SOGo exposes calendars, address books, and mail through open standards including CalDAV, CardDAV, GroupDAV, and Microsoft ActiveSync, so it works with native clients like Thunderbird, Outlook, Apple Calendar and Contacts, and mobile devices on iOS and Android.$q$, $q$It reuses existing infrastructure such as Active Directory, OpenLDAP, SQL databases, and IMAP mail servers, which reduces migration effort for organizations that already run this infrastructure. Its AJAX-based web interface supports drag-and-drop, single sign-on via CAS, WebAuth, or Kerberos, and two-factor authentication.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$SOGo's core server software is free and open source, released under the GNU GPL and LGPL version 2 licenses, so there is no license fee to install and run it on your own infrastructure. Organizations pay only for hosting and, optionally, commercial support contracts or a hosted variant such as Alinto's SOGomail.$q$, $q$Because pricing is not standardized like a typical SaaS product, actual cost depends on server infrastructure, in-house IT effort for maintenance and upgrades, and whether an organization purchases commercial support from Alinto or another provider.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2c574afd-be4a-449c-adfa-0158130d6f1d', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Prepaid Company Cards$q$, $q$Issue physical and virtual Mastercard prepaid cards to employees, departments, or projects with individual spending limits.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Spend Controls and Rules$q$, $q$Set budgets, category restrictions, and approval workflows per card or wallet to prevent overspending before it happens.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Receipt Capture and OCR$q$, $q$Employees capture receipts via mobile app, with OCR automatically extracting expense data to reduce manual entry.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Multi-Currency Spending$q$, $q$Plus and Unlimited plans support spending in multiple currencies, useful for businesses with international travel or teams.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Accounting Integrations$q$, $q$Sync transactions and expense data with accounting software to speed up reconciliation and month-end close.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Multiple Wallets$q$, $q$Create separate wallets for departments, projects, or cost centers to keep budgets and spending visible and separated.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Amazon Business and SAP Concur Integration$q$, $q$Connect Soldo to Amazon Business on the Plus plan or SAP Concur on the Unlimited plan for procurement and expense workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Role-Based Access Control$q$, $q$Assign granular permissions so administrators, approvers, and cardholders each see and control only what they need.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Combines company cards and expense software into a single platform, reducing manual expense reports$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Granular spending controls help prevent budget overruns before transactions happen$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Multi-currency support and OCR receipt capture are useful for international or high-volume spending teams$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Backed by significant funding and an established presence in the UK and European markets$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$30-day free trial available on the Standard and Plus plans$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Pricing is per plan plus per-card issuance fees, which can add up for larger card fleets$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Unlimited plan requires a sales demo rather than transparent self-serve pricing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Primarily focused on the UK and European markets, which may limit fit for US-only companies$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Some advanced integrations like SAP Concur are limited to the top-tier plan$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$What is Soldo used for$q$, $q$Soldo is used by finance teams to issue prepaid company cards and control employee, departmental, or project spending with built-in budgeting and expense automation.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$How much does Soldo cost$q$, $q$Soldo's Standard plan starts at 21 pounds per month, Plus is 33 pounds per month, and the Unlimited plan uses custom pricing based on company size and needs.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$When was Soldo founded$q$, $q$Soldo was founded in 2015 and is headquartered in London, United Kingdom.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Does Soldo offer a free trial$q$, $q$Yes, Soldo offers a 30-day free trial on its Standard and Plus plans.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Does Soldo support multiple currencies$q$, $q$Yes, multi-currency spending is available starting on the Plus plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$What accounting software does Soldo integrate with$q$, $q$Soldo integrates with popular accounting software for transaction syncing and reconciliation, with more advanced integrations like SAP Concur on the Unlimited plan.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Are Soldo cards physical or virtual$q$, $q$Soldo offers both physical prepaid Mastercards and virtual cards, each with its own issuance fee.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$How many employees does Soldo have$q$, $q$Soldo has more than 350 employees across offices in London, Milan, Rome, and Dublin.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Departmental Budget Control$q$, $q$Finance teams issue cards to each department with preset budgets so spending stays within limits without manual approval chains for every purchase.$q$, $q$Finance and operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Employee Expense Cards$q$, $q$Businesses replace expense reports and reimbursements with prepaid cards that automatically capture receipts and categorize spend.$q$, $q$SMBs and mid-market companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Project and Client Spend Tracking$q$, $q$Agencies and project-based businesses use separate wallets per client or project to track and bill back spend accurately.$q$, $q$Agencies and professional services firms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Standard$q$, $q$£21/month$q$, $q$Monthly (30-day free trial)$q$, NULL, $q$["1 wallet, 3 users, 3 cards","Up to 20 monthly bank transfers","Basic spend controls and permissions","Receipt capture via mobile app","Accounting software integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Plus$q$, $q$£33/month$q$, $q$Monthly (30-day free trial)$q$, NULL, $q$["3 company wallets","Up to 30 monthly bank transfers","Multi-currency spending","OCR receipt automation","Amazon Business integration","Advanced reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$Unlimited$q$, $q$Custom pricing$q$, $q$Annual contract (demo required)$q$, NULL, $q$["Unlimited wallets, users, and cards","Unlimited bank transfers","Role-based access control","Custom workflows and integrations","SAP Concur integration","Dedicated professional services team"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$overview$q$, $q$What Is Soldo$q$, 2, ARRAY[$q$Soldo is a spend management platform built around prepaid Mastercard company cards, giving finance teams control over who can spend money, how much, and on what, without relying on traditional expense reports or shared corporate credit cards.$q$, $q$Founded in 2015 and headquartered in London, United Kingdom, Soldo has grown into one of Europe's better-known fintech spend management providers, with additional offices in Milan, Rome, and Dublin and over 370 million dollars raised in funding.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Soldo issues both physical and virtual prepaid cards that can be assigned to employees, departments, or specific projects, each with its own spending rules, limits, and approval workflows set by finance administrators.$q$, $q$The platform automates expense capture with a mobile app, OCR receipt scanning, and automatic categorization, and it syncs transaction data with accounting software so finance teams can close the books faster without manual data entry.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6ce12cf9-c098-4e09-ae5e-0c9a0e32199a', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Soldo's UK pricing has three tiers: Standard at 21 pounds per month for 1 wallet, 3 users, and 3 cards; Plus at 33 pounds per month adding multi-currency spending and OCR automation; and Unlimited, a custom-priced plan for larger organizations with unlimited wallets, users, and cards plus SAP Concur integration.$q$, $q$Additional card issuance fees apply, including a one-time fee per physical card and a smaller fee per virtual card. Both Standard and Plus plans include a 30-day free trial.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Real-Time Solar Dashboard$q$, $q$View live production, consumption, battery, and grid data in a configurable, self-hosted dashboard.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Historical Data and Trends$q$, $q$Track production and consumption trends over days, months, and years to understand system performance.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Financial Savings Calculation$q$, $q$Automatically calculates the money saved and earned from self-consumption, battery use, and grid feed-in.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Battery Monitoring$q$, $q$Displays battery charge level, charge and discharge rates, and state of health for hybrid solar and storage systems.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Self-Hosted and Open Source$q$, $q$Runs entirely on your own infrastructure, with full source code available under the AGPL-3.0 license.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Docker Configurator$q$, $q$Generates a ready-to-use Docker Compose configuration through an online configurator for simplified setup.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Hardware Integrations$q$, $q$Connects to common inverters and energy-monitoring hardware to pull production and consumption data.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$AI and MCP Support$q$, $q$Exposes solar data through a Model Context Protocol server so AI assistants can answer natural-language questions about system performance.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Completely free and open source with no subscription fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Full data ownership since the dashboard is self-hosted rather than tied to a manufacturer's cloud app$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Detailed financial savings calculations help quantify the value of a solar investment$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Active development and a configurator that simplifies Docker-based deployment$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Requires self-hosting skills such as running a Raspberry Pi or Linux server and Docker$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Limited to users whose inverter or monitoring hardware is supported$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$No official managed cloud hosting option directly from the project$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Smaller community and documentation base compared to large commercial monitoring platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Is SOLECTRUS free$q$, $q$Yes, SOLECTRUS is free and open source under the AGPL-3.0 license. You only need your own hosting hardware, such as a Raspberry Pi or Linux server.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Who created SOLECTRUS$q$, $q$SOLECTRUS was created and is maintained by German developer Georg Ledermann, with development ongoing since around 2020.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$What hardware do I need to run SOLECTRUS$q$, $q$SOLECTRUS is typically self-hosted on a Raspberry Pi or any Linux server capable of running Docker, alongside a time-series database.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Does SOLECTRUS support battery systems$q$, $q$Yes, SOLECTRUS can monitor battery state of charge, charge and discharge rates, and overall storage system performance.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Can SOLECTRUS calculate savings from my solar system$q$, $q$Yes, it automatically calculates financial savings and earnings based on self-consumption, battery usage, and grid feed-in.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Is SOLECTRUS a cloud service$q$, $q$No, SOLECTRUS is self-hosted software. There is no official managed cloud version from the project itself.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Does SOLECTRUS work with AI assistants$q$, $q$Yes, SOLECTRUS offers a Model Context Protocol server so AI assistants like Claude can answer natural-language questions about your solar data.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Residential Solar Monitoring$q$, $q$Homeowners with rooftop solar and battery storage self-host SOLECTRUS to track production, consumption, and savings in real time.$q$, $q$Residential solar system owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Small Commercial PV Systems$q$, $q$Small businesses with on-site solar installations use SOLECTRUS to monitor system performance without a manufacturer subscription.$q$, $q$Small commercial solar operators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Solar Hobbyist Dashboards$q$, $q$Hobbyists and home automation enthusiasts integrate SOLECTRUS into their self-hosted smart home dashboards for detailed energy insights.$q$, $q$Home automation and solar hobbyists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under AGPL-3.0","Unlimited historical data retention, subject to your own storage","Real-time and historical dashboards","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$overview$q$, $q$What Is SOLECTRUS$q$, 2, ARRAY[$q$SOLECTRUS is a free, open-source dashboard that gives solar photovoltaic system owners real-time and historical visibility into how much energy they produce, consume, store in a battery, and exchange with the grid, along with automatically calculated cost savings.$q$, $q$The project is created and maintained by German developer Georg Ledermann, with active development since around 2020. It is self-hosted, typically running on a Raspberry Pi or a Linux server, and released under the AGPL-3.0 open-source license.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$SOLECTRUS visualizes solar production, household consumption, battery state of charge, and grid import and export in configurable dashboards, and it automatically calculates the financial savings generated by a solar installation over time.$q$, $q$The software integrates with common inverter and energy-monitoring hardware, and it can be deployed using an online configurator that generates a ready-to-use Docker setup, simplifying installation for users comfortable with self-hosting.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$SOLECTRUS is free and open source under the AGPL-3.0 license, so there is no subscription fee to download, install, and run it. Users are responsible for their own hosting hardware, such as a Raspberry Pi or small server, and any associated electricity or infrastructure costs.$q$, $q$Because SOLECTRUS is self-hosted rather than a managed SaaS product, there are no tiered subscription plans; the software itself is free, and the only ongoing cost is the infrastructure it runs on.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5a231e16-9bac-4260-965f-8748c267e354', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Time Entry Tracking$q$, $q$Log billable and non-billable time against clients, projects, and tasks with a simple, modern interface.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Client and Project Management$q$, $q$Organize work by client and project, with tags for further categorization and filtering.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Billable Rates$q$, $q$Set billable rates per client, project, or user to generate accurate invoices from tracked time.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Team Access Management$q$, $q$Manage roles and permissions at the project and organization level on the Professional plan.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Invoicing$q$, $q$Generate invoices directly from tracked billable time on the Professional plan.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Reporting and Exports$q$, $q$Create PDF and shareable reports to summarize time spent by client, project, or team member.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Self-Hosting$q$, $q$Deploy Solidtime on your own infrastructure for free using the open-source AGPL-3.0 licensed code.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Project and Task Estimates$q$, $q$Set time estimates for projects and tasks to track progress against budgeted hours on the Professional plan.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Free and open source with the option to self-host indefinitely at no cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Modern, clean interface compared to many legacy time tracking tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Transparent, low-cost paid tier for teams that want a managed cloud version$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Built-in invoicing and billable rate tracking suited to freelancers and agencies$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Newer project, founded around 2024, with a smaller feature set and community than established competitors like Toggl or Harvest$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Self-hosting requires technical setup and ongoing maintenance$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Fewer third-party integrations compared to mature commercial time trackers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Company size and long-term backing are not well documented, which may concern risk-averse enterprise buyers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Is Solidtime free$q$, $q$Yes, Solidtime offers a free Solo plan for individual freelancers, and the software can be self-hosted for free indefinitely under its AGPL-3.0 open-source license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$How much does Solidtime cost$q$, $q$Solidtime's Professional cloud plan costs 8 euros per user per month billed annually, or 9 euros per user per month billed monthly.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Can I self-host Solidtime$q$, $q$Yes, Solidtime's full source code is available on GitHub under the AGPL-3.0 license, and it can be self-hosted for free.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Who is Solidtime for$q$, $q$Solidtime is built for freelancers and agencies that need to track billable hours, manage clients and projects, and generate invoices and reports.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Where is Solidtime based$q$, $q$Solidtime is based in Vienna, Austria.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Does Solidtime support invoicing$q$, $q$Yes, invoicing is available on the Professional plan, generated directly from tracked billable time.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$What license does Solidtime use$q$, $q$Solidtime is released under the GNU Affero General Public License version 3, AGPL-3.0.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Freelancer Time and Billing$q$, $q$Freelancers track hours per client and project and use billable rates to prepare accurate invoices.$q$, $q$Freelancers and independent consultants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Agency Client Time Tracking$q$, $q$Small agencies track time across multiple client projects with role-based access for team members.$q$, $q$Small agencies and consultancies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Self-Hosted Time Tracking$q$, $q$Privacy-conscious teams self-host Solidtime on their own infrastructure to keep time and client data in-house.$q$, $q$Privacy-focused teams and IT departments$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Solo$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Time entry tracking","Clients, projects, tags and tasks","Billable hours and rates","Reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Professional$q$, $q$8 euros/user/month (annual) or 9 euros/user/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Team access management at project and organization level","Invoicing","Project and task estimates","Time entry rounding","PDF and shareable reports","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under AGPL-3.0","Unlimited users on your own infrastructure","Community support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$overview$q$, $q$What Is Solidtime$q$, 2, ARRAY[$q$Solidtime is an open-source time tracking application designed for freelancers and agencies that need to track billable hours, manage clients and projects, and generate reports, without paying for a closed-source SaaS subscription.$q$, $q$Founded around 2024 and based in Vienna, Austria, Solidtime is released under the AGPL-3.0 license with its full source code on GitHub. It can be self-hosted for free indefinitely, or used through Solidtime's managed cloud offering.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Solidtime tracks time entries against clients, projects, tags, and tasks, with support for billable rates so freelancers and agencies can invoice clients accurately based on logged hours.$q$, $q$The Professional plan adds team-level access management at both the project and organization level, invoicing, project and task estimates, time entry rounding, and exportable PDF or shareable reports, making it suitable for small agencies as well as solo freelancers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Solidtime's cloud pricing has two tiers: Solo, which is free and aimed at freelancers tracking their own time, and Professional, priced at 8 euros per user per month billed annually or 9 euros per user per month billed monthly, aimed at teams that bill clients and need access control.$q$, $q$Because Solidtime is open source, self-hosting the software remains free indefinitely under the AGPL-3.0 license. A separate on-premise pricing structure covers organizations that want commercial licensing terms or support beyond the free self-hosted option.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5c6ff423-a4cd-408d-b230-67dfd498aa1d', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Open Source Rails Engine$q$, $q$Solidus ships as a Ruby on Rails engine, giving developers full access to the source code and the ability to override any component.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Order and Payment Management$q$, $q$Built-in support for orders, multiple payment methods, and payment gateways out of the box.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Promotions Engine$q$, $q$Flexible promotions system for discounts, coupon codes, and rule-based pricing adjustments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Shipping Configuration$q$, $q$Configurable shipping methods, rates, and zones to support complex fulfillment needs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Extension Ecosystem$q$, $q$A library of community-maintained extensions adds functionality like subscriptions, marketplaces, and additional payment gateways.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Headless and API-Ready$q$, $q$Supports headless commerce architectures through its API, letting teams build custom storefronts on any frontend framework.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Multi-Store Support$q$, $q$Can be configured to run multiple storefronts or brands from a single Solidus backend.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Decentralized Governance$q$, $q$Maintained by a community-driven governance model with Project Directors and a Core Team rather than a single vendor, reducing platform lock-in risk.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Deep customizability through Rails' native override mechanisms and a Rails engine architecture$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Proven at scale by well-known direct-to-consumer brands$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Community-driven governance reduces the risk of a single vendor changing direction or shutting down$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Strong fit for headless commerce architectures via its API$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Requires in-house or agency Ruby on Rails expertise to implement and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$No official vendor support line; support comes from the community or paid agency partners$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Total cost of ownership can exceed hosted SaaS platforms once developer time is factored in$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Smaller ecosystem of extensions and integrations compared to platforms like Shopify$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Is Solidus free$q$, $q$Yes, Solidus is a free, open-source ecommerce framework. There is no license fee, though you pay for hosting, developer time, and any optional paid support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Who created Solidus$q$, $q$Solidus was created in 2015 by the consultancy Stembolt as a fork of Spree, aimed at greater stability and backward compatibility.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Who maintains Solidus today$q$, $q$Solidus is maintained by an open-source community under a decentralized governance model, with the Italian agency Nebulab as the largest code contributor.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$What is the difference between Solidus and Spree$q$, $q$Solidus is a fork of Spree created in 2015 to prioritize stability, easier upgrades, and backward compatibility after Spree's development direction became unstable.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$What companies use Solidus$q$, $q$Well-known brands that have used Solidus include Bonobos, Casper, Away, MeUndies, FLOYD, Maisonette, and Ace and Tate.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Does Solidus support headless commerce$q$, $q$Yes, Solidus exposes an API that supports headless commerce architectures, allowing teams to build a custom frontend on any framework.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Do I need Ruby on Rails experience to use Solidus$q$, $q$Yes, Solidus is built as a Ruby on Rails engine, so implementing and customizing it requires Rails development expertise.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Direct-to-Consumer Online Stores$q$, $q$Fashion, home goods, and consumer brands build fully customized online stores on Solidus to avoid the constraints of hosted SaaS platforms.$q$, $q$DTC brands and retailers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Headless Commerce Backends$q$, $q$Engineering teams use Solidus as an API-first backend paired with a custom frontend built in React or another framework.$q$, $q$Engineering and product teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Marketplace and Multi-Store Platforms$q$, $q$Companies running multiple brands or a marketplace configure Solidus to manage several storefronts from a single backend.$q$, $q$Multi-brand retailers and marketplace operators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under open-source license","Unlimited stores and products","Community support via GitHub and Slack","Access to community extensions"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$Agency Implementation and Support$q$, $q$Custom pricing$q$, $q$Project or retainer based$q$, NULL, $q$["Implementation services from Solidus partner agencies like Nebulab","Ongoing maintenance and support","Custom extension development"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$overview$q$, $q$What Is Solidus$q$, 2, ARRAY[$q$Solidus is a free, open-source ecommerce framework built on Ruby on Rails. It was created in 2015 as a fork of Spree by the consultancy Stembolt, which wanted a more stable, backward-compatible foundation for the online store it was building for the fashion brand Bonobos.$q$, $q$After Stembolt was acquired in 2018, the Solidus community reorganized under a decentralized governance model. The Italian software agency Nebulab is the largest code contributor today, and the project is overseen by a rotating group of Project Directors and a technical Core Team rather than a single company.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Solidus is structured as a Rails engine, giving developers a fully functional ecommerce backend covering products, orders, payments, promotions, and shipping, while allowing every part of the platform to be customized or overridden using Rails' native mechanisms.$q$, $q$It has been used in production by numerous direct-to-consumer brands, including Bonobos, Casper, Away, MeUndies, FLOYD, Maisonette, and Ace and Tate, demonstrating its ability to handle real-world, high-traffic ecommerce workloads.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Solidus itself is completely free and open source; there is no license fee to download, install, or modify the codebase. As a self-hosted Rails application, the actual cost of running a Solidus store comes from developer time, hosting infrastructure, and any third-party extensions or services you choose to integrate.$q$, $q$Organizations that want dedicated implementation help or ongoing support typically hire an agency such as Nebulab or another Solidus partner, and those engagements are priced individually rather than through a fixed subscription.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c34caf13-187c-4852-8539-3e8297879c3d', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Static Code Analysis$q$, $q$Scans source code across more than 30 languages and frameworks for bugs, vulnerabilities, and code smells.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Quality Gates$q$, $q$Blocks a build or pull request from merging if code does not meet configurable quality and security thresholds.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Secrets Detection$q$, $q$Detects hardcoded secrets and credentials across hundreds of known patterns in the Developer Edition and above.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$AI-Generated Code Detection$q$, $q$Identifies AI-generated code in a codebase to help teams apply appropriate review standards.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$AI CodeFix$q$, $q$Enterprise Edition includes AI-powered fix suggestions for flagged issues to speed up remediation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$CI/CD and DevOps Integration$q$, $q$Integrates with popular CI/CD tools and DevOps platforms like GitHub, GitLab, Azure DevOps, and Bitbucket.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Portfolio Management$q$, $q$Enterprise Edition adds portfolio-level dashboards for tracking code quality across many projects and teams.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$High Availability and Scalability$q$, $q$Data Center Edition adds component redundancy, horizontal scalability, and Kubernetes autoscaling for large distributed deployments.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Free Community Edition provides real static analysis value at no cost for individuals and small teams$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Supports a wide range of languages and integrates with most major CI/CD and DevOps platforms$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Self-hosted deployment gives full control over source code and data residency$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Scales from small teams to large enterprises with Data Center Edition's high availability features$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Backed by SonarSource, an established company founded in 2008 with hundreds of employees$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Enterprise and Data Center Edition pricing requires contacting sales rather than transparent self-serve pricing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Self-hosting requires infrastructure, installation, and ongoing maintenance effort$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Cost scales with lines of code, which can become expensive for very large codebases$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Some advanced features like AI CodeFix and portfolio management are limited to higher-tier editions$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Is SonarQube free$q$, $q$SonarQube's Community Edition is free and open source for self-hosted use. Paid Developer, Enterprise, and Data Center editions add features and scale, starting around 750 dollars per year.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$What is the difference between SonarQube and SonarQube Cloud$q$, $q$SonarQube (SonarQube Server) is a self-managed product you host yourself, while SonarQube Cloud, formerly SonarCloud, is SonarSource's hosted SaaS version. Both are made by SonarSource but priced and deployed differently.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$What languages does SonarQube support$q$, $q$SonarQube supports more than 30 programming languages and frameworks in its Developer Edition, with additional languages like COBOL and ABAP available in Enterprise Edition.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Who makes SonarQube$q$, $q$SonarQube is made by SonarSource, a company founded in 2008 and headquartered in Geneva, Switzerland.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$How is SonarQube priced$q$, $q$SonarQube is priced per instance per year based on the number of lines of code analyzed, not the number of users.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Does SonarQube integrate with CI/CD pipelines$q$, $q$Yes, SonarQube integrates with popular CI/CD tools and DevOps platforms, and can block pull requests or builds that fail configured quality gates.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$What is Data Center Edition for$q$, $q$Data Center Edition is designed for large, distributed engineering organizations that need high availability, horizontal scalability, and Kubernetes autoscaling for analyzing very large codebases.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Self-Hosted Code Quality Gates$q$, $q$Engineering teams add SonarQube to their CI/CD pipeline to block merges that introduce bugs, vulnerabilities, or excessive code smells.$q$, $q$Software engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Enterprise Security and Compliance$q$, $q$Large organizations use Enterprise or Data Center Edition to track code quality and security across many projects and enforce compliance standards like MISRA.$q$, $q$Enterprise DevSecOps and security teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Regulated or Air-Gapped Environments$q$, $q$Organizations that cannot use cloud SaaS tools deploy SonarQube on-premises to keep source code analysis entirely within their own infrastructure.$q$, $q$Government, finance, and regulated industries$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Community Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open-source static analysis","Supports popular languages including Java, JavaScript, Python, and C#","Community support only","Self-hosted deployment"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Developer Edition$q$, $q$From $750/year$q$, $q$Annual, per instance based on lines of code$q$, NULL, $q$["34 languages and frameworks","Advanced bug detection","Secrets detection across 400-plus patterns","AI-generated code detection","Commercial support available"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Enterprise Edition$q$, $q$Custom pricing$q$, $q$Annual, per instance based on lines of code$q$, NULL, $q$["40 total languages and frameworks","Unlimited DevOps platform integrations","Portfolio management and reporting","AI CodeFix","MISRA C++ compliance support","24/7 premium support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$Data Center Edition$q$, $q$Custom pricing$q$, $q$Annual, per instance based on lines of code$q$, NULL, $q$["Component redundancy and data resiliency","Horizontal scalability","Kubernetes autoscaling","High-performance capabilities for distributed teams"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$overview$q$, $q$What Is SonarQube$q$, 2, ARRAY[$q$SonarQube, also called SonarQube Server, is a self-managed static code analysis platform from SonarSource that scans source code for bugs, vulnerabilities, security hotspots, and code smells, helping engineering teams maintain code quality and security as part of their development workflow.$q$, $q$SonarSource was founded in 2008 and is headquartered in Geneva, Switzerland, with additional offices in Austin, Texas, Bochum, Germany, London, Singapore, and Tokyo. SonarQube is deployed on-premises or in an organization's own cloud infrastructure, distinguishing it from SonarQube Cloud, SonarSource's separately priced hosted SaaS product.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$SonarQube integrates directly into CI/CD pipelines and pull request workflows, automatically flagging bugs, vulnerabilities, and code smells across more than 30 languages and frameworks before code merges, with quality gates that can block a build if standards are not met.$q$, $q$Higher editions add capabilities such as secrets detection across hundreds of patterns, AI-generated code detection, AI CodeFix for automated remediation suggestions, portfolio-level reporting across many projects, and compliance support for standards like MISRA C++.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$SonarQube offers a free, open-source Community Edition for self-hosted use by individual developers and small teams. Paid editions are licensed per instance per year based on lines of code: Developer Edition starts around 750 dollars annually for around 100,000 lines of code, while Enterprise and Data Center Editions require contacting sales and are aimed at codebases of 1 million lines of code and above.$q$, $q$Because pricing scales with the size of the codebase being analyzed rather than the number of users, larger organizations should budget based on total lines of code across the projects they plan to scan, not headcount.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6ee2d4f-e582-42ed-987a-7a8f22539693', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Fully Managed SaaS Analysis$q$, $q$No servers to install or maintain; SonarQube Cloud connects directly to your source code host and runs analysis automatically.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Pull Request Decoration$q$, $q$Adds inline quality and security feedback directly on pull requests in GitHub, GitLab, Bitbucket, and Azure DevOps.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Branch Analysis$q$, $q$Analyzes every branch, not just the main branch, to catch issues earlier in the development process.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$30-Plus Language Support$q$, $q$Covers more than 30 programming languages and frameworks across the Free and Team plans.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Open Source Plan$q$, $q$Offers a dedicated free plan for public open-source repositories, separate from the private-project free tier.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Enterprise SSO and Compliance$q$, $q$Enterprise plan adds SAML and SCIM single sign-on, audit logs, IP allow lists, and security and regulatory reports.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Portfolio and Enterprise Hierarchy$q$, $q$Enterprise plan lets large organizations group many projects into portfolios for aggregated reporting.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Enterprise Language Support$q$, $q$Enterprise plan adds support for languages like COBOL, ABAP, JCL, RPG, PL/I, and Apex used in legacy and enterprise systems.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$No infrastructure to manage since it is a fully hosted SaaS product$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Free tier is generous enough for small private projects and fully free for open-source repositories$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Deep, native integration with GitHub, GitLab, Bitbucket, and Azure DevOps pull request workflows$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Scales cleanly from individual developers to large enterprises via lines-of-code-based pricing$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Backed by SonarSource, an established vendor with a long track record in code quality tooling$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Pricing scales with lines of code, which can become expensive for very large codebases$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Enterprise plan requires annual billing and a custom sales quote rather than transparent pricing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Code is analyzed on SonarSource's cloud infrastructure, which may not suit organizations with strict data residency requirements$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Free tier's 50,000 line limit for private projects is easy to outgrow for actively developed codebases$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Is SonarQube Cloud the same as SonarCloud$q$, $q$Yes, SonarQube Cloud is the renamed version of SonarCloud, SonarSource's hosted SaaS code quality and security product.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Is SonarQube Cloud free$q$, $q$Yes, SonarQube Cloud offers a free tier for private projects up to 50,000 lines of code, and a separate free plan for open-source projects.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$How much does the SonarQube Cloud Team plan cost$q$, $q$The Team plan starts around 34 dollars per month for up to 100,000 lines of code, with pricing increasing in tiers up to 1.9 million lines of code.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$What is the difference between SonarQube Cloud and SonarQube Server$q$, $q$SonarQube Cloud is a fully managed SaaS product hosted by SonarSource, while SonarQube Server, SonarQube, is self-managed software you install and run on your own infrastructure. Both are made by SonarSource but priced and deployed differently.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Does SonarQube Cloud support pull request analysis$q$, $q$Yes, SonarQube Cloud automatically decorates pull requests with inline quality and security feedback in GitHub, GitLab, Bitbucket, and Azure DevOps.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Does SonarQube Cloud offer single sign-on$q$, $q$Yes, single sign-on via SAML and SCIM is available on the Enterprise plan.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Who makes SonarQube Cloud$q$, $q$SonarQube Cloud is made by SonarSource, a company founded in 2008 and headquartered in Geneva, Switzerland.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$SaaS Pull Request Quality Checks$q$, $q$Development teams connect SonarQube Cloud to their GitHub or GitLab repositories to automatically check every pull request for bugs and vulnerabilities.$q$, $q$Software development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Open Source Project Analysis$q$, $q$Open-source maintainers use SonarQube Cloud's free open-source plan to keep public repositories free of quality and security issues.$q$, $q$Open-source maintainers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Enterprise Portfolio Code Quality$q$, $q$Large enterprises use the Enterprise plan to track code quality and security across hundreds of projects organized into portfolios, with SSO and audit logging.$q$, $q$Enterprise engineering and security leadership$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Private projects up to 50,000 lines of code","30-plus language support","Branch analysis","Pull request decoration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$SonarQube for Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited lines of code for public open-source repositories","Full pull request and branch analysis","Community support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Team$q$, $q$From $34/month$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 100,000 lines of code at entry pricing, scaling to 1.9 million LOC","Full language support","Branch and pull request analysis","Standard support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$Enterprise$q$, $q$Custom pricing based on lines of code$q$, $q$Annual only$q$, NULL, $q$["No upper limit on lines of code","Single sign-on via SAML and SCIM","Security and regulatory reports","Customizable dashboards","Enterprise hierarchy and portfolio creation","Audit logs and IP allow lists","Enterprise languages including COBOL, ABAP, JCL, RPG, PL/I, and Apex"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$overview$q$, $q$What Is SonarQube Cloud$q$, 2, ARRAY[$q$SonarQube Cloud, formerly called SonarCloud, is the fully managed, hosted version of SonarSource's code quality and security analysis platform. Instead of installing and maintaining a server, teams connect their GitHub, GitLab, Bitbucket, or Azure DevOps repositories directly to SonarQube Cloud, and it automatically analyzes commits, branches, and pull requests.$q$, $q$SonarQube Cloud is built by SonarSource, founded in 2008 and headquartered in Geneva, Switzerland. It is a separate product from SonarQube Server, the self-managed, on-premises version, with its own pricing model based on lines of code analyzed rather than per-instance annual licensing.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$SonarQube Cloud automatically decorates pull requests with inline quality and security feedback, supports branch analysis, and covers more than 30 programming languages and frameworks, all without requiring customers to provision or maintain analysis server infrastructure.$q$, $q$The Enterprise plan adds capabilities aimed at larger organizations, including single sign-on via SAML and SCIM, security and regulatory compliance reports, customizable dashboards, an enterprise hierarchy for organizing many projects into portfolios, audit logs, IP allow lists, and support for enterprise languages such as COBOL, ABAP, JCL, RPG, PL/I, and Apex.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('19756a8e-09b5-44fb-801b-926184dbba14', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$SonarQube Cloud's Free plan supports private projects up to 50,000 lines of code, with a separate free plan available for open-source projects. The Team plan starts around 34 dollars per month for up to 100,000 lines of code, with additional lines-of-code increments available up to 1.9 million, billed monthly or annually.$q$, $q$The Enterprise plan is billed annually only, priced based on total lines of code with no upper limit, and requires contacting SonarSource sales for a quote, since pricing depends on codebase size and specific enterprise feature requirements.$q$]::text[], 2);
