-- Enrichment marathon batch: Softr, SOGo, Soldo, SOLECTRUS, Solidtime, Solidus, SonarQube, SonarQube Cloud

-- ── Softr ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Softr is a no-code and AI-native platform for building business apps, client portals, and internal tools directly from data in Airtable, Google Sheets, HubSpot, and SQL databases.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $49/month)$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Berlin, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Softr Pricing, Features and Reviews (2026)$q$, seo_title),
  seo_meta_description = COALESCE($q$Softr is an AI-native no-code platform for building business apps and client portals from your data. See pricing, features, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Softr is a no-code and AI-native application builder that lets businesses turn existing data from Airtable, Google Sheets, Notion, HubSpot, SQL databases, and 15-plus other sources into fully functional web apps, client portals, and internal tools without writing code. Founded in 2019 in Berlin, Germany by Mariam Hakobyan and Artur Mkrtchyan, Softr raised a 13.5 million dollar Series A led by FirstMark Capital and has grown into a widely used platform for startups, agencies, and internal-tools teams. Softr apps include user authentication, role-based permissions, workflows and automations, payments, and a professional, responsive UI that can be customized with custom code blocks. The platform offers a free plan supporting up to 10 users and 5,000 database records, alongside paid tiers: Basic at 49 dollars per month, Professional at 139 dollars per month, and Business at 269 dollars per month, plus a custom-priced Enterprise plan with SSO, SOC2 reporting, and audit logging. Higher tiers unlock more app users, AI credits, database records, custom user groups, and advanced data-source integrations such as HubSpot, BigQuery, PostgreSQL, and MySQL. Softr is best suited for teams that want to launch client portals, internal dashboards, marketplaces, or directories quickly, without hiring developers, while still allowing custom code for advanced needs.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3c1c11fd-4faf-4d6c-8f2f-a21304ececf9';

