-- ── SOGo ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$SOGo is a free, open-source groupware and webmail server offering email, calendars, and contacts with CalDAV, CardDAV, and ActiveSync support for self-hosted collaboration.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2004, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$German$q$, $q$Spanish$q$]::text[],
  seo_title = COALESCE($q$SOGo: Open Source Groupware and Webmail Server$q$, seo_title),
  seo_meta_description = COALESCE($q$SOGo is a free open-source groupware server with webmail, calendars, and contacts via CalDAV, CardDAV, and ActiveSync. See features and pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SOGo is a free and open-source groupware and webmail server designed for businesses and organizations that want to self-host email, calendaring, and contact management instead of relying on a hosted service. Its roots trace back to LSOffice in 1996 and the SKYRiX and OpenGroupware.org projects developed by Skyrix Software in Magdeburg, Germany; the current SOGo project began in 2004 as a scalability-focused fork. The Canadian company Inverse maintained SOGo for many years, and since 2022 the French company Alinto has served as its commercial steward, offering paid support and a hosted variant called SOGomail. SOGo is released under the GNU GPL and LGPL version 2 licenses, so the core server software is free to download, install, and modify, with costs limited to hosting infrastructure or optional commercial support contracts. It provides an AJAX-based web interface plus native client support through CalDAV, CardDAV, GroupDAV, and Microsoft ActiveSync, allowing synchronization with Thunderbird, Outlook, Apple Calendar and Contacts, and mobile devices. SOGo integrates with existing directory and mail infrastructure such as Active Directory, OpenLDAP, SQL databases, and IMAP servers, and it is used in production environments with thousands of mailboxes, most commonly by hosting providers, ISPs, and IT teams that need a self-hosted Exchange-like alternative.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2c574afd-be4a-449c-adfa-0158130d6f1d';

