-- ── Soldo ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Soldo is a spend management platform that combines prepaid company cards with expense automation, budgeting, and approval controls for businesses.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$£21/month$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$351-500 employees$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Italian$q$]::text[],
  seo_title = COALESCE($q$Soldo Pricing and Features: Spend Management Cards$q$, seo_title),
  seo_meta_description = COALESCE($q$Soldo offers prepaid company cards with expense automation and budget controls. Compare Soldo pricing plans, features, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Soldo is a spend management platform that issues prepaid Mastercard company cards, both physical and virtual, paired with software for budgeting, expense automation, and approval workflows. Founded in 2015 and headquartered in London, United Kingdom, with additional offices in Milan, Rome, and Dublin, Soldo has raised more than 370 million dollars across multiple funding rounds, including a Series C, and employs over 350 people. The platform lets finance teams set spending rules and budgets per card, department, or project, automatically categorize expenses, capture receipts via mobile app and OCR, and sync transactions with accounting software. Soldo offers three main pricing tiers on its UK site: Standard at 21 pounds per month including 1 wallet and 3 cards, Plus at 33 pounds per month with multi-currency spending and OCR automation, and a custom-priced Unlimited plan with unlimited wallets, cards, and users plus SAP Concur integration and a dedicated professional services team. Soldo is aimed at small and mid-size businesses through larger enterprises that need to control employee and departmental spending without relying on manual expense reports or corporate credit cards, and it competes with products like Pleo, Payhawk, and Airbase in the European spend management market.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6ce12cf9-c098-4e09-ae5e-0c9a0e32199a';

