-- ── SOLECTRUS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$SOLECTRUS is a free, open-source, self-hosted dashboard for monitoring solar PV production, consumption, battery usage, grid exchange, and savings.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$SOLECTRUS: Open Source Solar Monitoring Dashboard$q$, seo_title),
  seo_meta_description = COALESCE($q$SOLECTRUS is a free, self-hosted dashboard for monitoring solar production, consumption, battery, and grid data. See features and setup options.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SOLECTRUS is a free and open-source, self-hosted dashboard for monitoring photovoltaic solar systems, tracking production, household consumption, battery charge and discharge, grid import and export, and the financial savings a solar installation generates. Created and maintained by German developer Georg Ledermann starting around 2020, the project is released under the AGPL-3.0 open-source license, though the SOLECTRUS name and logo remain trademarks of its creator. The software is designed to run on a Raspberry Pi or any Linux server, typically alongside a time-series database, and users can generate a ready-to-use Docker configuration through an online configurator at configurator.solectrus.de. SOLECTRUS pulls data from common inverter and energy-monitoring hardware and presents it in real-time and historical dashboards, letting solar system owners see at a glance how much energy they are producing, using, storing, and feeding back to the grid, along with automatically calculated cost savings. The project also offers a Model Context Protocol server, allowing AI assistants such as Claude to answer natural-language questions about a user's solar data. SOLECTRUS is aimed at residential and small commercial solar system owners, and hobbyists who want detailed, self-hosted visibility into their energy system without relying on a manufacturer's proprietary cloud app.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5a231e16-9bac-4260-965f-8748c267e354';

