-- ── Solidtime ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Solidtime is an open-source time tracking app for freelancers and teams, available as a free self-hosted deployment or a paid managed cloud plan.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2024, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Vienna, Austria$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Solidtime: Open Source Time Tracking Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Solidtime is an open-source time tracking app for freelancers and teams. Compare free self-hosted and paid cloud pricing plans and features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Solidtime is an open-source time tracking application built for freelancers, agencies, and teams that want a modern alternative to expensive, closed-source SaaS time trackers such as Toggl or Harvest. Founded around 2024 and based in Vienna, Austria, Solidtime is released under the AGPL-3.0 license, with the full source code available on GitHub, meaning it can be self-hosted for free indefinitely. The company also offers a managed cloud version with a Solo plan that is free for individual freelancers and a Professional plan priced at 8 euros per user per month when billed annually, or 9 euros per user per month billed monthly. The Professional plan adds team access management, invoicing, project and task estimates, time entry rounding, and PDF or shareable reports. Core features available across plans include time entry tracking, clients, projects, tags, tasks, billable hours and rates, and reporting. A separate on-premise pricing structure exists for organizations that want to self-host with a commercial license and support beyond the free open-source option. Solidtime is best suited for freelancers who bill clients by the hour, small agencies managing multiple client projects, and privacy-conscious teams that prefer to self-host rather than rely on a third-party SaaS provider.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5c6ff423-a4cd-408d-b230-67dfd498aa1d';

