-- ── Solidus ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Solidus is a free, open-source ecommerce framework built on Ruby on Rails, forked from Spree, used by direct-to-consumer brands for fully customizable online stores.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Solidus: Open Source Ruby on Rails Ecommerce$q$, seo_title),
  seo_meta_description = COALESCE($q$Solidus is a free, open-source ecommerce platform built on Ruby on Rails. Learn about features, governance, pricing, and who uses Solidus.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Solidus is a free, open-source ecommerce framework built on Ruby on Rails, created in 2015 when the consultancy Stembolt forked Spree to prioritize stability, backward compatibility, and easier upgrades. After Stembolt was acquired by JUUL Labs in 2018, the Solidus community reorganized under a decentralized governance model, with the Italian software agency Nebulab serving as the largest code contributor and a rotating group of Project Directors and a Core Team overseeing the project's technical and business direction. Because Solidus is a Rails engine rather than a hosted product, it is entirely free to use, and there is no vendor-set subscription price; costs come from hosting, developer time, and optional commercial support purchased from agencies like Nebulab. Solidus ships with a functional backend out of the box, covering products, orders, payments, promotions, and shipping, while being designed for deep customization through Rails' native override mechanisms and built-in extensions. It has been used in production by well-known direct-to-consumer brands including Bonobos, Casper, Away, MeUndies, and Ace and Tate. Solidus is best suited for engineering teams that want full control over their ecommerce codebase and are comfortable working in Ruby on Rails, rather than businesses looking for a no-code or fully managed SaaS storefront.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c34caf13-187c-4852-8539-3e8297879c3d';

