-- ── SonarQube ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$SonarQube is a self-managed static code analysis platform by SonarSource that continuously checks code quality, bugs, vulnerabilities, and code smells across 30-plus languages.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community Edition); paid plans from $750/year$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE($q$501-1000 employees$q$, company_size),
  headquarters = COALESCE($q$Geneva, Switzerland$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$SonarQube Pricing and Plans: Server Editions Explained$q$, seo_title),
  seo_meta_description = COALESCE($q$SonarQube is a self-managed code quality and security platform by SonarSource. Compare Community, Developer, Enterprise, and Data Center pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SonarQube, now marketed as SonarQube Server, is a self-managed static code analysis platform built by SonarSource, a company founded in 2008 and headquartered in Geneva, Switzerland, with additional offices including Austin, Texas. SonarQube continuously scans source code for bugs, vulnerabilities, security hotspots, and code smells across more than 30 programming languages and frameworks, integrating into CI/CD pipelines and pull request workflows so issues are caught before code reaches production. A free, open-source Community Edition is available for individual developers and small teams who self-host the server. Paid editions unlock additional capability and scale: Developer Edition starts around 750 dollars per year for codebases around 100,000 lines of code and adds features like secrets detection and AI-generated code detection; Enterprise Edition, priced by contacting sales, adds portfolio management, unlimited DevOps platform integrations, and AI CodeFix for larger codebases starting around 1 million lines of code; and Data Center Edition adds high availability, horizontal scalability, and Kubernetes autoscaling for the largest, most distributed engineering organizations. SonarQube analyzes hundreds of billions of lines of code daily across its user base and is widely used by engineering and DevSecOps teams that require an on-premises or self-hosted code quality and security solution rather than a cloud SaaS product, for which SonarSource separately offers SonarQube Cloud.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c6ee2d4f-e582-42ed-987a-7a8f22539693';

