  seo_title = COALESCE($q$SonarQube Cloud Pricing: Free, Team, and Enterprise$q$, seo_title),
  seo_meta_description = COALESCE($q$SonarQube Cloud, formerly SonarCloud, is SonarSource's hosted code quality SaaS. Compare Free, Team, and Enterprise pricing plans and features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SonarQube Cloud, formerly known as SonarCloud, is the hosted SaaS code quality and security product from SonarSource, the company founded in 2008 and headquartered in Geneva, Switzerland, that also makes the self-managed SonarQube Server product. Unlike SonarQube Server, which organizations install and run on their own infrastructure, SonarQube Cloud is a fully managed service that connects directly to source code hosts like GitHub, GitLab, Bitbucket, and Azure DevOps, automatically analyzing pull requests and branches without requiring customers to manage servers. SonarQube Cloud offers a free tier for exploring the product with private projects up to 50,000 lines of code, plus a separate free plan for open-source projects, supporting 30-plus languages, branch analysis, and pull request decoration. The paid Team plan starts around 34 dollars per month for up to 100,000 lines of code, with pricing scaling in increments up to 1.9 million lines of code, billed monthly or annually. The Enterprise plan, available only on an annual billing cycle and priced based on lines of code with no upper limit, adds single sign-on via SAML and SCIM, security and regulatory reports, customizable dashboards, enterprise hierarchy and portfolio creation, audit logs, IP allow lists, and support for enterprise languages such as COBOL and ABAP. SonarQube Cloud is best suited for teams that want code quality and security scanning without operating their own SonarQube server infrastructure.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '19756a8e-09b5-44fb-801b-926184dbba14';

